class String (  SpireObject) :
    """

    """
    @dispatch
    def __init__(self):
        dlllib.spr_pdf_String_Create.restype = c_void_p
        intPtr = CallCFunction(dlllib.spr_pdf_String_Create)
        super(String, self).__init__(intPtr)
    @dispatch
    def __init__(self, value:str):
        if __package__ == "spire.presentation.common":
            valuePtr = StrToPtr(value)
            dlllib.spr_pdf_String_CreateV.argtypes=[ c_void_p]
            dlllib.spr_pdf_String_CreateV.restype = c_void_p
            intPtr = CallCFunction(dlllib.spr_pdf_String_CreateV,valuePtr)
            super(String, self).__init__(intPtr)
        else:
            dlllib.spr_pdf_String_CreateV.argtypes=[ c_wchar_p]
            dlllib.spr_pdf_String_CreateV.restype = c_void_p
            intPtr = CallCFunction(dlllib.spr_pdf_String_CreateV,value)
            super(String, self).__init__(intPtr)

    def __str__(self):
        return self.Value

    @property
    def Value(self)->str:
        """

        """
        dlllib.spr_pdf_String_Value.argtypes=[ c_void_p]
        dlllib.spr_pdf_String_Value.restype=c_void_p
        ret = PtrToStr(CallCFunction(dlllib.spr_pdf_String_Value, self.Ptr))
        return ret

